// The 3 decks to create. deckKey drives the layout in 'Build requests'.
return [
  { json: { deckKey: 'boardpack', title: 'CWSI Board Pack \u2014 TEMPLATE' } },
  { json: { deckKey: 'kpi', title: 'CWSI KPI Register \u2014 TEMPLATE' } },
  { json: { deckKey: 'pipeline', title: 'CWSI Pipeline \u2014 TEMPLATE' } },
];

// Build the Slides batchUpdate requests that lay out one template deck.
// Reads the just-created presentation ($json) + its deckKey (from 'Deck list').
const res = $json;
const presentationId = res.presentationId;
const defaultSlideId = (res.slides && res.slides[0]) ? res.slides[0].objectId : null;
const deckKey = $('Deck list').item.json.deckKey;

const NAVY = '#0a2c52', INK = '#0f172a', MUTE = '#78869c', WHITE = '#ffffff', PALE = '#cfe1f7';
function hexToRgb(h) { const n = parseInt(h.replace('#',''),16); return { red:((n>>16)&255)/255, green:((n>>8)&255)/255, blue:(n&255)/255 }; }
let seq = 0; const uid = (p) => deckKey + '_' + p + '_' + (seq++);
const reqs = [];
function addSlide() { const id = uid('s'); reqs.push({ createSlide: { objectId: id, slideLayoutReference: { predefinedLayout: 'BLANK' } } }); return id; }
function setBg(sid, hex) { reqs.push({ updatePageProperties: { objectId: sid, pageProperties: { pageBackgroundFill: { solidFill: { color: { rgbColor: hexToRgb(hex) } } } }, fields: 'pageBackgroundFill.solidFill.color' } }); }
function box(sid, x, y, w, h, text, o) { o = o || {}; const id = uid('b'); reqs.push({ createShape: { objectId: id, shapeType: 'TEXT_BOX', elementProperties: { pageObjectId: sid, size: { width: { magnitude: w, unit: 'PT' }, height: { magnitude: h, unit: 'PT' } }, transform: { scaleX: 1, scaleY: 1, translateX: x, translateY: y, unit: 'PT' } } } }); if (text && text.length) { reqs.push({ insertText: { objectId: id, text: text } }); reqs.push({ updateTextStyle: { objectId: id, style: { fontFamily: 'Manrope', fontSize: { magnitude: o.size || 12, unit: 'PT' }, bold: !!o.bold, foregroundColor: { opaqueColor: { rgbColor: hexToRgb(o.color || INK) } } }, fields: 'fontFamily,fontSize,bold,foregroundColor', textRange: { type: 'ALL' } } }); } return id; }

const m = (i, f) => '{{m' + i + '_' + f + '}}';
const metricLines = [];
for (let i = 1; i <= 7; i++) metricLines.push(m(i,'label') + ': ' + m(i,'value') + '   (target ' + m(i,'target') + ' \u00b7 ' + m(i,'pct') + ' \u00b7 ' + m(i,'status') + ')');
const funnelLines = ['Leads: {{leads}}', 'MQLs: {{mql}}', 'SQLs: {{sql}}', 'Opportunities: {{opp}}', 'Pipeline: {{pipeline_gbp}}', 'Closed-won: {{closed_won_gbp}}'];
const footLines = ['{{confidentiality}}', '{{contact}}', 'Generated {{generated_date}}'];

const DECKS = {
  boardpack: [
    { cover: true, title: '{{report_title}}', scope: '{{scope_line}}' },
    { title: 'Executive Summary', lines: ['{{exec_summary}}'] },
    { title: 'Top-line KPIs', lines: metricLines, charts: ['[[KPI_CHART]]'] },
    { title: 'Pipeline Funnel', lines: funnelLines, charts: ['[[FUNNEL_CHART]]'] },
    { title: 'By Channel', lines: ['Channel mix \u2014 see chart.'], charts: ['[[CHANNEL_CHART]]'] },
    { title: 'Gaps to Close', lines: ['1. {{lever1_title}} \u2014 gap {{lever1_gap}} \u00b7 impact {{lever1_impact}}', '2. {{lever2_title}} \u2014 gap {{lever2_gap}} \u00b7 impact {{lever2_impact}}', '3. {{lever3_title}} \u2014 gap {{lever3_gap}} \u00b7 impact {{lever3_impact}}'] },
    { title: 'Closing', lines: footLines }
  ],
  kpi: [
    { cover: true, title: '{{report_title}}', scope: '{{scope_line}}' },
    { title: 'Executive Summary', lines: ['{{exec_summary}}'] },
    { title: 'KPI Register', lines: ['Full register \u2014 see table.'], charts: ['[[KPI_TABLE]]', '[[KPI_CHART]]'] },
    { title: 'Closing', lines: footLines }
  ],
  pipeline: [
    { cover: true, title: '{{report_title}}', scope: '{{scope_line}}' },
    { title: 'Pipeline Funnel', lines: funnelLines, charts: ['[[FUNNEL_CHART]]'] },
    { title: 'Open Pipeline by Stage', lines: ['Stage breakdown \u2014 see table.'], charts: ['[[STAGE_TABLE]]'] },
    { title: 'Closing', lines: footLines }
  ]
};

const slides = DECKS[deckKey] || [];
for (const s of slides) {
  const sid = addSlide();
  if (s.cover) {
    setBg(sid, NAVY);
    box(sid, 40, 34, 300, 44, 'CWSI.', { size: 26, bold: true, color: WHITE });
    box(sid, 40, 150, 640, 90, s.title, { size: 34, bold: true, color: WHITE });
    box(sid, 40, 250, 640, 40, s.scope, { size: 16, color: PALE });
    continue;
  }
  if (s.title) box(sid, 40, 28, 640, 38, s.title, { size: 22, bold: true, color: NAVY });
  if (s.lines && s.lines.length) box(sid, 40, 84, 640, 210, s.lines.join('\n'), { size: 13, color: INK });
  if (s.charts) s.charts.forEach((c, idx) => box(sid, 40 + idx * 230, 310, 210, 70, c, { size: 11, color: MUTE }));
}
if (defaultSlideId) reqs.push({ deleteObject: { objectId: defaultSlideId } });

return { json: { presentationId: presentationId, deckKey: deckKey, title: $('Deck list').item.json.title, requests: reqs } };

// Tidy summary: the 3 TEMPLATE_IDs + edit URLs to copy and send back.
return $('Build requests').all().map((i) => ({ json: {
  deck: i.json.deckKey,
  title: i.json.title,
  TEMPLATE_ID: i.json.presentationId,
  edit_url: 'https://docs.google.com/presentation/d/' + i.json.presentationId + '/edit',
} }));
